(function() {
  'use strict';

  var VERSION = '2.2.0';
  var PROCESSED = 'data-ba-dl';

  if (window.__igDlCleanup) {
    try { window.__igDlCleanup(); } catch(e) {}
  }

  /* ── Styles ─────────────────────────────────────────── */
  if (!document.getElementById('ba-ig-dl-styles')) {
    var style = document.createElement('style');
    style.id = 'ba-ig-dl-styles';
    style.textContent = [
      /* Trigger — circular icon button */
      '.ba-dl-trigger{display:inline-flex;align-items:center;justify-content:center;width:40px;height:40px;border-radius:50%;border:none;background:transparent;cursor:pointer;padding:0;transition:transform .15s,background .15s;position:relative;flex-shrink:0}',
      '.ba-dl-trigger:hover{background:rgba(0,0,0,.06);transform:scale(1.08)}',
      '.ba-dl-trigger:active{transform:scale(.94)}',
      '.ba-dl-trigger svg{width:24px;height:24px;fill:#262626;transition:fill .15s}',
      '.ba-dl-trigger:hover svg{fill:#0095f6}',
      '',
      '/* Popup panel */',
      '.ba-dl-popup{position:absolute;z-index:2147483647;min-width:240px;max-width:300px;background:#1a1a2e;border:1px solid rgba(255,255,255,.08);border-radius:12px;box-shadow:0 12px 40px rgba(0,0,0,.45),0 2px 8px rgba(0,0,0,.2);padding:8px;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;color:#e0e0e0;backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);animation:ba-dl-in .15s ease-out}',
      '@keyframes ba-dl-in{from{opacity:0;transform:translateY(-4px)}to{opacity:1;transform:translateY(0)}}',
      '',
      '/* Section header */',
      '.ba-dl-header{display:flex;align-items:center;gap:6px;padding:4px 8px 6px;font-size:11px;font-weight:600;color:rgba(255,255,255,.4);text-transform:uppercase;letter-spacing:.6px}',
      '.ba-dl-header svg{width:12px;height:12px;fill:rgba(255,255,255,.35)}',
      '',
      '/* Media item row */',
      '.ba-dl-item{display:flex;align-items:center;gap:10px;padding:8px;border-radius:8px;transition:background .1s;cursor:pointer;border:none;background:none;width:100%;text-align:left;color:#e0e0e0;font-family:inherit;font-size:13px;line-height:1.3}',
      '.ba-dl-item:hover{background:rgba(255,255,255,.08)}',
      '.ba-dl-item:active{background:rgba(255,255,255,.12)}',
      '',
      '/* Type icon */',
      '.ba-dl-icon{display:flex;align-items:center;justify-content:center;width:32px;height:32px;border-radius:8px;flex-shrink:0}',
      '.ba-dl-icon--photo{background:rgba(0,149,246,.12)}',
      '.ba-dl-icon--photo svg{width:16px;height:16px;fill:#0095f6}',
      '.ba-dl-icon--video{background:rgba(237,73,86,.12)}',
      '.ba-dl-icon--video svg{width:16px;height:16px;fill:#ed4956}',
      '',
      '/* Labels */',
      '.ba-dl-label{font-weight:600;color:#e0e0e0}',
      '.ba-dl-meta{font-size:11px;color:rgba(255,255,255,.35);margin-top:1px}',
      '',
      '/* Current-media badge */',
      '.ba-dl-badge{display:inline-block;padding:1px 5px;border-radius:3px;background:rgba(0,149,246,.18);color:#58b1f0;font-size:10px;font-weight:700;letter-spacing:.3px;margin-left:6px;vertical-align:middle}',
      '',
      '/* Divider */',
      '.ba-dl-sep{height:1px;background:rgba(255,255,255,.06);margin:4px 0}',
      '',
      '/* Download All */',
      '.ba-dl-all{display:flex;align-items:center;justify-content:center;gap:6px;width:100%;padding:9px 12px;margin-top:4px;border:1px solid rgba(0,149,246,.25);border-radius:8px;background:rgba(0,149,246,.08);color:#58b1f0;font-size:13px;font-weight:600;font-family:inherit;cursor:pointer;transition:background .12s,border-color .12s}',
      '.ba-dl-all:hover{background:rgba(0,149,246,.18);border-color:rgba(0,149,246,.45)}',
      '.ba-dl-all svg{width:14px;height:14px;fill:#58b1f0}',
      '',
      '/* Story overlay trigger */',
      '.ba-dl-trigger--story{position:absolute;bottom:68px;right:16px;z-index:9999;background:rgba(0,0,0,.5);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);border:1px solid rgba(255,255,255,.12)}',
      '.ba-dl-trigger--story svg{fill:#fff}',
      '.ba-dl-trigger--story:hover{background:rgba(0,0,0,.7)}',
      '.ba-dl-trigger--story:hover svg{fill:#fff}',
      '',
      '/* Dark-mode IG support */',
      '[class*="x1n2onr6"][style*="color: rgb(245"] .ba-dl-trigger svg{fill:#f5f5f5}',
      '[class*="x1n2onr6"][style*="color: rgb(245"] .ba-dl-trigger:hover{background:rgba(255,255,255,.1)}'
    ].join('\n');
    document.head.appendChild(style);
  }

  /* ── SVG Icons ──────────────────────────────────────── */
  var IC = {
    dl: '<svg viewBox="0 0 24 24"><path d="M12 15.575l-4.95-4.95 1.414-1.414L11 11.747V3h2v8.747l2.536-2.536 1.414 1.414L12 15.575zM5 19h14v-4h2v5a1 1 0 01-1 1H4a1 1 0 01-1-1v-5h2v4z"/></svg>',
    photo: '<svg viewBox="0 0 24 24"><path d="M5 3h14a2 2 0 012 2v14a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2zm0 2v10.586l4-4 3 3 4-4 4 4V5H5zm0 14h14v-1.414l-4-4-4 4-3-3-3 3V19zM8.5 11A1.5 1.5 0 118.5 8a1.5 1.5 0 010 3z"/></svg>',
    video: '<svg viewBox="0 0 24 24"><path d="M3 3.993C3 3.445 3.445 3 3.993 3h16.014c.548 0 .993.445.993.993v16.014a.994.994 0 01-.993.993H3.993A.994.994 0 013 20.007V3.993zM5 5v14h14V5H5zm4.622 3.415l4.879 3.252a.4.4 0 010 .666l-4.879 3.252A.4.4 0 019 15.319V8.681a.4.4 0 01.622-.266z"/></svg>',
    allDl: '<svg viewBox="0 0 24 24"><path d="M6 13l-1.414 1.414L12 21.828l7.414-7.414L18 13l-5 5V2h-2v16l-5-5zM2 22h20v2H2v-2z"/></svg>'
  };

  /* ── State ──────────────────────────────────────────── */
  var activePopup = null;
  var activeTarget = null;

  function closePopup() {
    if (activePopup) {
      activePopup.remove();
      activePopup = null;
      activeTarget = null;
    }
  }

  document.addEventListener('click', function(e) {
    if (activePopup && !activePopup.contains(e.target) && !e.target.closest('.ba-dl-trigger')) {
      closePopup();
    }
  }, true);

  /* ── Download helper ───────────────────────────────── */
  function dlMedia(url, isVideo) {
    var fname = 'instagram_' + Date.now() + (isVideo ? '.mp4' : '.jpg');
    fetch(url, { mode: 'cors' })
      .then(function(r) {
        if (!r.ok) throw new Error(r.status);
        return r.blob();
      })
      .then(function(blob) {
        var u = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = u;
        a.download = fname;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(function() { URL.revokeObjectURL(u); }, 5000);
      })
      .catch(function() {
        /* Blob download failed — open the direct URL so the user can save manually */
        window.open(url, '_blank', 'noopener');
      });
  }

  /* ── Media detection ───────────────────────────────── */
  function bestSrc(img) {
    var srcset = img.getAttribute('srcset');
    if (srcset) {
      var parts = srcset.split(',').map(function(s) { return s.trim(); });
      return parts[parts.length - 1].split(' ')[0];
    }
    return img.src;
  }

  function getAllMedia(container) {
    var imgs = [], vids = [];
    container.querySelectorAll('video[src], video source[src]').forEach(function(v) {
      var s = v.src || v.getAttribute('src');
      if (s && vids.indexOf(s) === -1) vids.push(s);
    });
    container.querySelectorAll('img[srcset], img[src]').forEach(function(img) {
      var w = img.width || img.naturalWidth; var h = img.height || img.naturalHeight;
      if (w < 50 || h < 50) return;
      if (img.closest('header')) return;
      var src = bestSrc(img);
      if (src && src.indexOf('s150x150') === -1 && imgs.indexOf(src) === -1) {
        imgs.push(src);
      }
    });
    return { images: imgs, videos: vids };
  }

  function getCurrentMedia(article) {
    var ar = article.getBoundingClientRect();
    /* Visible video */
    var vid = article.querySelector('video[src]');
    if (vid) {
      var vr = vid.getBoundingClientRect();
      if (vr.left >= ar.left - 20 && vr.right <= ar.right + 20 && vr.width > 100) {
        return { url: vid.src, isVideo: true };
      }
    }
    /* Largest visible image */
    var best = null, bestArea = 0;
    article.querySelectorAll('img[srcset], img[src]').forEach(function(img) {
      if (img.width < 50 || img.height < 50 || img.closest('header')) return;
      var r = img.getBoundingClientRect();
      if (r.left >= ar.left - 20 && r.right <= ar.right + 20 && r.width > 100) {
        var area = r.width * r.height;
        if (area > bestArea) { bestArea = area; best = img; }
      }
    });
    if (best) {
      var src = bestSrc(best);
      if (src && src.indexOf('s150x150') === -1) return { url: src, isVideo: false };
    }
    return null;
  }



  /* ── Carousel & API helpers ──────────────────────── */
  function getPostShortcode(container) {
    var link = container.querySelector('a[href*="/p/"], a[href*="/reel/"]');
    if (!link) return null;
    var href = link.getAttribute('href') || '';
    var match = href.match(/\/(p|reel)\/([A-Za-z0-9_-]+)/);
    return match ? match[2] : null;
  }

  function getCarouselCount(container) {
    return container.querySelectorAll('._acnb').length;
  }

  function fetchMediaFromApi(shortcode) {
    return fetchViaInfoEndpoint(shortcode)
      .then(function(items) {
        if (items && items.length > 0) return items;
        return fetchViaGraphQL(shortcode);
      })
      .catch(function() { return null; });
  }

  function fetchViaInfoEndpoint(shortcode) {
    return fetch('/p/' + shortcode + '/?__a=1&__d=dis', {
      credentials: 'include',
      headers: { 'X-IG-App-ID': '936619743392459', 'X-Requested-With': 'XMLHttpRequest' }
    })
    .then(function(r) { if (!r.ok) throw new Error(r.status); return r.json(); })
    .then(function(json) { return parseApiResponse(json); })
    .catch(function() { return null; });
  }

  function fetchViaGraphQL(shortcode) {
    var url = '/graphql/query/?query_hash=b3055c01b4b222b8a47dc12b090e4e64&variables=' +
      encodeURIComponent(JSON.stringify({ shortcode: shortcode, child_comment_count: 0, fetch_comment_count: 0, parent_comment_count: 0, has_threaded_comments: false }));
    return fetch(url, {
      credentials: 'include',
      headers: { 'X-IG-App-ID': '936619743392459', 'X-Requested-With': 'XMLHttpRequest' }
    })
    .then(function(r) { if (!r.ok) throw new Error(r.status); return r.json(); })
    .then(function(json) {
      if (json.data && json.data.shortcode_media) {
        return parseGraphQLMedia(json.data.shortcode_media);
      }
      return null;
    })
    .catch(function() { return null; });
  }

  function parseApiResponse(json) {
    var items = [];
    var media = null;
    if (json.graphql && json.graphql.shortcode_media) media = json.graphql.shortcode_media;
    else if (json.items && json.items[0]) media = json.items[0];
    if (!media) return items;

    /* GraphQL format */
    if (media.edge_sidecar_to_children && media.edge_sidecar_to_children.edges) {
      return parseGraphQLMedia(media);
    }

    /* Items API format */
    if (media.carousel_media) {
      media.carousel_media.forEach(function(cm) {
        var isVideo = cm.media_type === 2 || !!cm.video_versions;
        var url;
        if (isVideo && cm.video_versions && cm.video_versions[0]) url = cm.video_versions[0].url;
        else if (cm.image_versions2 && cm.image_versions2.candidates && cm.image_versions2.candidates[0]) url = cm.image_versions2.candidates[0].url;
        if (url) items.push({ url: url, isVideo: isVideo });
      });
      return items;
    }

    /* Single media */
    var isVideo = media.is_video || media.media_type === 2;
    var url;
    if (isVideo) url = media.video_url || (media.video_versions && media.video_versions[0] ? media.video_versions[0].url : null);
    else url = media.display_url || (media.image_versions2 && media.image_versions2.candidates && media.image_versions2.candidates[0] ? media.image_versions2.candidates[0].url : null);
    if (url) items.push({ url: url, isVideo: !!isVideo });
    return items;
  }

  function parseGraphQLMedia(media) {
    var items = [];
    if (media.edge_sidecar_to_children && media.edge_sidecar_to_children.edges) {
      media.edge_sidecar_to_children.edges.forEach(function(edge) {
        var node = edge.node;
        items.push({ url: node.is_video ? node.video_url : node.display_url, isVideo: !!node.is_video });
      });
    } else {
      var isVideo = !!media.is_video;
      items.push({ url: isVideo ? media.video_url : media.display_url, isVideo: isVideo });
    }
    return items;
  }

  /* ── Popup builder ─────────────────────────────────── */
  function showPopup(trigger, container, allItems, current, isStory) {
    var total = allItems.length;
    if (total === 0) return;

    var popup = document.createElement('div');
    popup.className = 'ba-dl-popup';

    /* Header */
    var hdr = document.createElement('div');
    hdr.className = 'ba-dl-header';
    hdr.innerHTML = IC.dl + '<span>' + total + ' item' + (total > 1 ? 's' : '') + '</span>';
    popup.appendChild(hdr);

    /* Current media (carousel-aware) */
    if (current) {
      var curBtn = document.createElement('button');
      curBtn.className = 'ba-dl-item';
      var iconCls = current.isVideo ? 'ba-dl-icon ba-dl-icon--video' : 'ba-dl-icon ba-dl-icon--photo';
      var typeLabel = current.isVideo ? 'Video' : 'Photo';
      curBtn.innerHTML =
        '<span class="' + iconCls + '">' + (current.isVideo ? IC.video : IC.photo) + '</span>' +
        '<span><span class="ba-dl-label">' + typeLabel + '</span>' +
        (total > 1 ? '<span class="ba-dl-badge">viewing</span>' : '') +
        '<div class="ba-dl-meta">Download current</div></span>';
      curBtn.addEventListener('click', function(e) {
        e.preventDefault(); e.stopPropagation();
        dlMedia(current.url, current.isVideo);
        closePopup();
      });
      popup.appendChild(curBtn);
    }

    /* Individual items + Download All (multi-media only) */
    if (total > 1) {
      popup.appendChild(Object.assign(document.createElement('div'), { className: 'ba-dl-sep' }));

      allItems.forEach(function(item, idx) {
        var btn = document.createElement('button');
        btn.className = 'ba-dl-item';
        btn.innerHTML =
          '<span class="ba-dl-icon ba-dl-icon--' + (item.isVideo ? 'video' : 'photo') + '">' + (item.isVideo ? IC.video : IC.photo) + '</span>' +
          '<span><span class="ba-dl-label">' + (item.isVideo ? 'Video' : 'Photo') + ' ' + (idx + 1) + '</span></span>';
        btn.addEventListener('click', function(e) {
          e.preventDefault(); e.stopPropagation();
          dlMedia(item.url, item.isVideo);
          closePopup();
        });
        popup.appendChild(btn);
      });

      /* Download All */
      var allBtn = document.createElement('button');
      allBtn.className = 'ba-dl-all';
      allBtn.innerHTML = IC.allDl + ' Download All (' + total + ')';
      allBtn.addEventListener('click', function(e) {
        e.preventDefault(); e.stopPropagation();
        allItems.forEach(function(item) { dlMedia(item.url, item.isVideo); });
        closePopup();
      });
      popup.appendChild(allBtn);
    }

    document.body.appendChild(popup);
    activePopup = popup;
    activeTarget = container;

    /* Position relative to trigger */
    var tr = trigger.getBoundingClientRect();
    var pr = popup.getBoundingClientRect();
    var left = tr.left + window.scrollX + (tr.width / 2) - (pr.width / 2);
    var top = tr.bottom + window.scrollY + 8;
    if (left + pr.width > window.innerWidth - 8) left = window.innerWidth - pr.width - 8;
    if (left < 8) left = 8;
    if (top + pr.height > window.scrollY + window.innerHeight - 8) {
      top = tr.top + window.scrollY - pr.height - 8;
    }
    popup.style.left = left + 'px';
    popup.style.top = top + 'px';
  }

  function openPopup(trigger, container, isStory) {
    if (activeTarget === container) { closePopup(); return; }
    closePopup();

    var current = isStory ? null : getCurrentMedia(container);
    var domMedia = getAllMedia(container);
    var domItems = [];
    domMedia.images.forEach(function(url) { domItems.push({ url: url, isVideo: false }); });
    domMedia.videos.forEach(function(url) { domItems.push({ url: url, isVideo: true }); });

    var shortcode = isStory ? null : getPostShortcode(container);
    var carouselCount = getCarouselCount(container);

    /* For carousels, always try API since DOM only has 2-3 slides loaded */
    if (shortcode && carouselCount > 1) {
      fetchMediaFromApi(shortcode).then(function(apiItems) {
        if (apiItems && apiItems.length > 0) {
          showPopup(trigger, container, apiItems, current, isStory);
        } else {
          showPopup(trigger, container, domItems, current, isStory);
        }
      });
    } else {
      showPopup(trigger, container, domItems, current, isStory);
    }
  }

  /* ── Process posts ─────────────────────────────────── */
  function processPost(article) {
    if (article.getAttribute(PROCESSED)) return;
    var media = getAllMedia(article);
    if (media.images.length === 0 && media.videos.length === 0) return;
    article.setAttribute(PROCESSED, '1');

    var btn = document.createElement('button');
    btn.className = 'ba-dl-trigger';
    btn.title = 'Download media';
    btn.innerHTML = IC.dl;
    btn.addEventListener('click', function(e) {
      e.preventDefault(); e.stopPropagation();
      openPopup(btn, article, false);
    });

    /* Insert into the action-icon row */
    var section = article.querySelector('section');
    if (section) {
      var row = section.querySelector('span') || section.firstElementChild;
      if (row && row.parentElement === section) {
        row.appendChild(btn);
      } else {
        section.insertBefore(btn, section.firstChild);
      }
    } else {
      article.appendChild(btn);
    }
  }

  /* ── Stories ────────────────────────────────────────── */
  function processStories() {
    var targets = [
      { sel: '[role="presentation"] video[src]', isVideo: true },
      { sel: '[role="dialog"] video[src]', isVideo: true },
      { sel: '[role="presentation"] img[srcset]', isVideo: false },
      { sel: '[role="dialog"] img[decoding="sync"]', isVideo: false }
    ];
    targets.forEach(function(t) {
      var el = document.querySelector(t.sel);
      if (!el) return;
      var parent = el.closest('[role="presentation"]') || el.closest('[role="dialog"]');
      if (!parent || parent.querySelector('.ba-dl-trigger')) return;
      parent.setAttribute(PROCESSED, '1');
      parent.style.position = 'relative';

      var btn = document.createElement('button');
      btn.className = 'ba-dl-trigger ba-dl-trigger--story';
      btn.title = 'Download';
      btn.innerHTML = IC.dl;
      btn.addEventListener('click', function(e) {
        e.preventDefault(); e.stopPropagation();
        openPopup(btn, parent, true);
      });
      parent.appendChild(btn);
    });
  }

  /* ── Profile picture ───────────────────────────────── */
  function processProfilePic() {
    var header = document.querySelector('header');
    if (!header || header.getAttribute(PROCESSED)) return;
    var avatar = header.querySelector('img[alt*="profile picture"], img[data-testid="user-avatar"]');
    if (!avatar || !avatar.src) return;

    var fullSrc = avatar.src.replace(/\/s\d+x\d+\//, '/').replace(/\/c\d+\.\d+\.\d+\.\d+\//, '/');
    header.setAttribute(PROCESSED, '1');

    var btn = document.createElement('button');
    btn.className = 'ba-dl-trigger';
    btn.title = 'Download profile picture';
    btn.innerHTML = IC.dl;
    btn.addEventListener('click', function(e) {
      e.preventDefault(); e.stopPropagation();
      dlMedia(fullSrc, false);
    });

    var avatarParent = avatar.closest('span') || avatar.parentElement;
    if (avatarParent && avatarParent.parentElement) {
      avatarParent.parentElement.appendChild(btn);
    }
  }

  /* ── Main loop ─────────────────────────────────────── */
  function processAll() {
    document.querySelectorAll('article').forEach(processPost);
    processStories();
    processProfilePic();
  }

  processAll();

  var debounceTimer = null;
  var observer = new MutationObserver(function() {
    if (debounceTimer) clearTimeout(debounceTimer);
    debounceTimer = setTimeout(processAll, 300);
  });
  observer.observe(document.body, { childList: true, subtree: true });

  /* SPA navigation — reset on URL change */
  var lastUrl = location.href;
  var urlCheck = setInterval(function() {
    if (location.href !== lastUrl) {
      lastUrl = location.href;
      closePopup();
      document.querySelectorAll('[' + PROCESSED + ']').forEach(function(el) {
        el.removeAttribute(PROCESSED);
        var t = el.querySelector('.ba-dl-trigger');
        if (t) t.remove();
      });
      setTimeout(processAll, 500);
    }
  }, 1000);

  /* Cleanup for re-injection */
  window.__igDlCleanup = function() {
    observer.disconnect();
    if (debounceTimer) clearTimeout(debounceTimer);
    clearInterval(urlCheck);
    closePopup();
    document.querySelectorAll('.ba-dl-trigger').forEach(function(el) { el.remove(); });
    document.querySelectorAll('[' + PROCESSED + ']').forEach(function(el) {
      el.removeAttribute(PROCESSED);
    });
  };

  console.log('[Instagram Download Button v' + VERSION + '] Active');
})();
